import pandas as pddef calculate_moving_average(df, window=7):    """    Calculate the moving average of the closing price.    The moving average smooths price movement and helps show the general trend.    """    if df is None or df.empty or "Close" not in df.columns:        return pd.Series(dtype="float64")    return df["Close"].rolling(window=window).mean()def calculate_daily_return(df):    """    Calculate the latest percentage change between the last two closing prices.    """    if df is None or df.empty or "Close" not in df.columns or len(df) < 2:        return None    previous_close = df["Close"].iloc[-2]    latest_close = df["Close"].iloc[-1]    if previous_close == 0:        return None    return ((latest_close - previous_close) / previous_close) * 100def calculate_volatility(df):    """    Calculate volatility using the standard deviation of percentage returns.    """    if df is None or df.empty or "Close" not in df.columns or len(df) < 2:        return None    returns = df["Close"].pct_change().dropna()    if returns.empty:        return None    return returns.std() * 100def calculate_highest_price(df):    """    Return the highest price in the selected timeframe.    """    if df is None or df.empty or "High" not in df.columns:        return None    return df["High"].max()def calculate_lowest_price(df):    """    Return the lowest price in the selected timeframe.    """    if df is None or df.empty or "Low" not in df.columns:        return None    return df["Low"].min()def calculate_max_drawdown(df):    """    Calculate the maximum drawdown for the selected timeframe.    Drawdown measures the largest percentage fall from a previous high.    """    if df is None or df.empty or "Close" not in df.columns or len(df) < 2:        return None    cumulative_max = df["Close"].cummax()    drawdown = (df["Close"] - cumulative_max) / cumulative_max    return drawdown.min() * 100def calculate_market_indicators(df, moving_average_window=7):    """    Calculate a group of market indicators for the selected data.    """    if df is None or df.empty:        return {            "latest_close": None,            "moving_average": None,            "daily_return": None,            "volatility": None,            "highest_price": None,            "lowest_price": None,            "max_drawdown": None,        }    moving_average_series = calculate_moving_average(df, moving_average_window)    latest_moving_average = None    if not moving_average_series.empty and not pd.isna(moving_average_series.iloc[-1]):        latest_moving_average = moving_average_series.iloc[-1]    return {        "latest_close": df["Close"].iloc[-1] if "Close" in df.columns else None,        "moving_average": latest_moving_average,        "daily_return": calculate_daily_return(df),        "volatility": calculate_volatility(df),        "highest_price": calculate_highest_price(df),        "lowest_price": calculate_lowest_price(df),        "max_drawdown": calculate_max_drawdown(df),    }